
def findMaxConsecutiveOnes(nums):
    prevOneCounter = 0
    currentOneCounter = 0
    for item in nums:
        if(item == 1):
            currentOneCounter += 1
        else:
            if(currentOneCounter >= prevOneCounter):
                prevOneCounter = currentOneCounter
                currentOneCounter = 0
    return prevOneCounter if prevOneCounter > currentOneCounter else currentOneCounter
